    private fun executeAsync(client: OkHttpClient, request: Request, callback: IoTResponseCallback) {
        client.newCall(request).enqueue(object : Callback {
            override fun onFailure(call: Call, e: IOException) {
                Log.e(TAG, "Request failed: ${request.url}", e)
                callback.onError(e)
            }

            override fun onResponse(call: Call, response: Response) {
                response.use {
                    val bodyString = it.body?.string()
                    val iotResponse = IoTResponse(
                        statusCode = it.code,
                        body = bodyString,
                        headers = it.headers.toMap(),
                        isSuccessful = it.isSuccessful,
                        url = request.url.toString()
                    )

                    if (it.isSuccessful) {
                        Log.d(TAG, "Request successful: ${request.url} -> ${it.code}")
                        callback.onSuccess(iotResponse)
                    } else {
                        Log.w(TAG, "Request returned error: ${request.url} -> ${it.code}")
                        callback.onError(
                            IoTHttpException(it.code, bodyString ?: "No response body", request.url.toString())
                        )
                    }
                }
            }
        })
    }

    @Throws(IOException::class)
    private fun executeSync(client: OkHttpClient, request: Request): IoTResponse {
        val response = client.newCall(request).execute()
        return response.use {
            IoTResponse(
                statusCode = it.code,
                body = it.body?.string(),
                headers = it.headers.toMap(),
                isSuccessful = it.isSuccessful,
                url = request.url.toString()
            )
        }
    }

    private fun Headers.toMap(): Map<String, String> {
        val map = mutableMapOf<String, String>()
        for (i in 0 until size) {
            map[name(i)] = value(i)
