// --- Data Classes & Enums ---

enum class HttpMethod {
    GET, POST, PUT, DELETE, PATCH
}

data class IoTResponse(
    val statusCode: Int,
    val body: String?,
    val headers: Map<String, String>,
    val isSuccessful: Boolean,
    val url: String
) {
    fun bodyAsJson(): JSONObject? {
        return body?.let {
            try {
                JSONObject(it)
            } catch (e: Exception) {
                null
            }
        }
    }
}

data class DiscoveredDevice(
    val ip: String,
    val port: Int,
    val statusCode: Int,
    val responseBody: String?
)

class IoTHttpException(
    val statusCode: Int,
    val responseBody: String,
    val url: String
) : IOException("HTTP $statusCode from $url: $responseBody")

// --- Callback Interfaces ---

interface IoTResponseCallback {
    fun onSuccess(response: IoTResponse)
    fun onError(exception: Exception)
}

interface DeviceDiscoveryCallback {
    fun onDeviceFound(ip: String, statusCode: Int, responseBody: String?)
    fun onDiscoveryComplete(devices: List<DiscoveredDevice>)
}

// --- Interceptors ---

class LoggingInterceptor : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        val startTime = System.nanoTime()

        Log.d("IoTHttpClient", "--> ${request.method} ${request.url}")

        val response = chain.proceed(request)

        val duration = (System.nanoTime() - startTime) / 1_000_000
        Log.d("IoTHttpClient", "<-- ${response.code} ${request.url} (${duration}ms)")

        return response
    }
}

class RetryInterceptor(private val maxRetries: Int = 3) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()
        var lastException: IOException? = null

        for (attempt in 0..maxRetries) {
            try {
                val response = chain.proceed(request)
                if (response.isSuccessful || attempt >= maxRetries) {
                    return response
                }
                // Close unsuccessful response before retrying
                if (response.code in 500..599) {
                    response.close()
                    Log.w("IoTHttpClient", "Retry attempt ${attempt + 1} for ${request.url} (status: ${response.code})")
                } else {
                    return response
                }
            } catch (e: IOException) {
                lastException = e
                Log.w("IoTHttpClient", "Retry attempt ${attempt + 1} for ${request.url}: ${e.message}")
                if (attempt < maxRetries) {
                    try {
                        Thread.sleep((attempt + 1) * 1000L)
                    } catch (ie: InterruptedException) {
                        Thread.currentThread().interrupt()
                        throw e
                    }
                }
            }
        }

        throw lastException ?: IOException("Request failed after $maxRetries retries")
    }
}

// --- Example Activity Usage ---

class IoTExampleActivity : AppCompatActivity() {

    private val iotClient = IoTHttpClient.getInstance()

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Example: Get device status from local IoT device (HTTP)
        getLocalDeviceStatus("192.168.1.100")

        // Example: Send command to local IoT device
        sendDeviceCommand("192.168.1.100", "toggle_light", true)

        // Example: Fetch data from cloud API (HTTPS)
        fetchCloudDevices("your_auth_token_here")

        // Example: Register device with cloud
        registerDeviceWithCloud("device-001", "Smart Light", "your_auth_token_here")

        // Example: Discover devices on local network
        discoverLocalDevices()

        // Example: Generic request
        genericRequestExample()
    }

    private fun getLocalDeviceStatus(deviceIp: String) {
        iotClient.deviceGet(
            deviceIp = deviceIp,
            port = 80,
            path = "/api/status",
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    val json = response.bodyAsJson()
                    runOnUiThread {
                        Log.d("IoTExample", "Device status: $json")
                    }
                }

                override fun onError(exception: Exception) {
                    Log.e("IoTExample", "Failed to get device status", exception)
                }
            }
        )
    }

    private fun sendDeviceCommand(deviceIp: String, command: String, value: Boolean) {
        val body = JSONObject().apply {
            put("command", command)
            put("value", value)
            put("timestamp", System.currentTimeMillis())
        }

        iotClient.devicePost(
            deviceIp = deviceIp,
            port = 80,
            path = "/api/command",
            jsonBody = body,
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    Log.d("IoTExample", "Command sent successfully: ${response.body}")
                }

                override fun onError(exception: Exception) {
                    Log.e("IoTExample", "Failed to send command", exception)
                }
            }
        )
    }

    private fun fetchCloudDevices(authToken: String) {
        iotClient.cloudGet(
            endpoint = "/v1/devices",
            authToken = authToken,
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    val json = response.bodyAsJson()
                    runOnUiThread {
                        Log.d("IoTExample", "Cloud devices: $json")
                    }
                }

                override fun onError(exception: Exception) {
                    if (exception is IoTHttpException) {
                        Log.e("IoTExample", "Cloud API error ${exception.statusCode}: ${exception.responseBody}")
                    } else {
                        Log.e("IoTExample", "Failed to fetch cloud devices", exception)
                    }
                }
            }
        )
    }

    private fun registerDeviceWithCloud(deviceId: String, deviceName: String, authToken: String) {
        val body = JSONObject().apply {
            put("device_id", deviceId)
            put("name", deviceName)
            put("type", "smart_light")
            put("firmware_version", "1.2.3")
        }

        iotClient.cloudPost(
            endpoint = "/v1/devices/register",
            jsonBody = body,
            authToken = authToken,
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    Log.d("IoTExample", "Device registered: ${response.body}")
                }

                override fun onError(exception: Exception) {
                    Log.e("IoTExample", "Failed to register device", exception)
                }
            }
        )
    }

    private fun discoverLocalDevices() {
        iotClient.discoverDevices(
            subnet = "192.168.1",
            port = 80,
            path = "/api/info",
            callback = object : DeviceDiscoveryCallback {
                override fun onDeviceFound(ip: String, statusCode: Int, responseBody: String?) {
                    Log.d("IoTExample", "Found device at $ip (status: $statusCode)")
                }

                override fun onDiscoveryComplete(devices: List<DiscoveredDevice>) {
                    Log.d("IoTExample", "Discovery complete. Found ${devices.size} devices.")
                    devices.forEach { device ->
                        Log.d("IoTExample", "  - ${device.ip}:${device.port} -> ${device.responseBody}")
                    }
                }
            }
        )
    }

    private fun genericRequestExample() {
        // Auto-selects local client for local IPs, secure client for cloud URLs
        iotClient.request(
            url = "http://192.168.1.50:8080/api/sensor/temperature",
            method = HttpMethod.GET,
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    Log.d("IoTExample", "Sensor data: ${response.body}")
                }

                override fun onError(exception: Exception) {
                    Log.e("IoTExample", "Failed to read sensor", exception)
                }
            }
        )

        iotClient.request(
            url = "https://api.example.com/v1/telemetry",
            method = HttpMethod.POST,
            jsonBody = JSONObject().apply {
                put("temperature", 22.5)
                put("humidity", 65)
            },
            headers = mapOf("Authorization" to "Bearer token123"),
            callback = object : IoTResponseCallback {
                override fun onSuccess(response: IoTResponse) {
                    Log.d("IoTExample", "Telemetry sent: ${response.body}")
                }

                override fun onError(exception: Exception) {
                    Log.e("IoTExample", "Failed to send telemetry", exception)
                }
            }
        )
    }

    override fun onDestroy() {
        super.onDestroy()
        // Optionally shutdown the client when the activity is destroyed
        // iotClient.shutdown()
    }
}